1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Premium: empty policy and base premiums =====
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("single sword → 100 base + 10 first insurance + 5 fee = 115 G", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
17	    });
18	    expect(result).toEqual({ results: [{ premium: 115 }] });
19	  });
20	  it("single amulet → 60 base + 6 first insurance + 5 fee = 71 G", () => {
21	    const result = runScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 71 }] });
26	  });
27	  it.todo("single staff → base 80 + fee 5 = 85 G");
28	  it.todo("single potion → base 40 + fee 5 = 45 G");
29	
30	  // ===== Components and block-of-3 discount =====
31	  it.todo("single rune (component) → base 25 + fee 5 = 30 G");
32	  it.todo("2 runes → 50 G base premium (no block) + 5 G fee = 55 G");
33	  it.todo("3 runes → 60 G base premium (block) + 5 G fee = 65 G");
34	  it.todo("4 runes → 100 G base premium (no block, requires exactly 3) + 5 G fee = 105 G");
35	  it.todo("7 runes → 175 G base premium (one block of 3 + 4 single) + 5 G fee = 180 G");
36	
37	  // ===== "Alike" components — same type only =====
38	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types) + 5 G fee = 80 G");
39	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks) + 5 G fee = 125 G");
40	
41	  // ===== Item-specific modifiers =====
42	  it.todo("cursed sword adds 50% surcharge → 100 + 50 + 5 = 155 G");
43	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge → 100 + 30 + 5 = 135 G");
44	  it.todo("sword with enchantment 4 has no high-enchantment surcharge → 100 + 5 = 105 G");
45	  it.todo("cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 + 5 = 185 G)");
46	
47	  // ===== Policy-wide modifiers =====
48	  it.todo("customer with exactly 2 years gets 20% loyalty discount → sword: 100 - 20 + 5 = 85 G");
49	  it.todo("first insurance adds 10% initial assessment surcharge → sword: 100 + 10 + 5 = 115 G");
50	  it.todo("follow-up contract (second quote) gets 15% discount → sword: 100 - 15 + 5 = 90 G");
51	
52	  // ===== Modifier scope on multi-item policies =====
53	  it.todo("cursed sword + plain amulet → 160 base + 50 curse = 210 G + 5 fee = 215 G");
54	
55	  // ===== Rounding =====
56	  it.todo("premium fractions rounded up (in MHPCO's favor) — e.g., 197.5 → 198 G");
57	
58	  // ===== Integration examples =====
59	  it.todo("newcomer with cursed sword (0 yrs, first contract, ench 3) → 165 G");
60	  it.todo("long-standing customer's second contract cursed sword (3 yrs, ench 7) → 160 G");
61	
62	  // ===== Quote error handling =====
63	  it.todo("quote with unknown item type → CLI exits non-zero with stderr message");
64	
65	  // ===== Claims: standard reimbursement =====
66	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 - 100 deductible)");
67	  it.todo("rune damage 200 G → payout 100 G (200 - 100 deductible)");
68	
69	  // ===== Claims: special clauses =====
70	  it.todo("dragon-material sword full reimbursement: ench 5, damage 800 → payout 700");
71	  it.todo("high-enchantment (≥8) sword: steel ench 9, damage 1000 → payout 400 (50% then deductible)");
72	  it.todo("both clauses apply: dragon sword ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
73	  it.todo("dragon sword exactly enchantment 8, damage 1000 → payout 400 (50% clause applies, then deductible)");
74	
75	  // ===== Deductible per damage event =====
76	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
77	
78	  // ===== Multiple items of same type =====
79	  it.todo("two swords, each damaged 500 by dragon → payout 800 (deductible applied to each)");
80	  it.todo("two sword damages but only one sword insured → CLI exits non-zero");
81	
82	  // ===== Cap rules =====
83	  it.todo("sword + amulet insurance sum 1600, cap 3200 enforced");
84	  it.todo("cursed sword cap based on unmodified insurance value: cap 2000");
85	  it.todo("sword + 3 runes (block): insurance sum 1750 (block discount doesn't affect sum)");
86	  it.todo("two successive 1500 claims on sword (cap 2000): first payout 1400, then 600");
87	
88	  // ===== Claim error handling =====
89	  it.todo("claim references item not in policy (amulet damage with only sword insured) → CLI exits non-zero");
90	  it.todo("claim with negative damage amount → CLI exits non-zero");
91	
92	  // ===== Payout rounding =====
93	  it.todo("payout fractions rounded down (in MHPCO's favor) — e.g., 350.5 → 350 G");
94	});
