1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const ITEM_BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type Step = QuoteStep;
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
13	
14	const itemBase = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
15	
16	const quotePremium = (items: Item[]): number => {
17	  const policyBase = items.reduce((sum, item) => sum + itemBase(item), 0);
18	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
19	  return Math.ceil(policyBase + firstInsurance) + PROCESSING_FEE;
20	};
21	
22	export const runScenario = (scenario: Scenario): unknown => {
23	  const results = scenario.steps.map((step) => ({
24	    premium: quotePremium(step.items),
25	  }));
26	  return { results };
27	};
